const allRows = $input.all().map(item => item.json);

// 2. Retrieve Context Safely
let contextNode = {};

try {
    // FIXED: Must exactly match the node name "Map Context1"
    if ($node["Map Context1"] && $node["Map Context1"].json) {
        contextNode = $node["Map Context1"].json;
    } else if (allRows.length > 0 && allRows[0].user_role) {
        contextNode = allRows[0];
    } else if ($input.first().json.context) {
        contextNode = $input.first().json;
    }
} catch (error) {
    contextNode = { user_role: 'guest', request_type: 'chat', module_filter: 'home' };
}

// ---------------------------------------------------------
// USE ROLE DIRECTLY (NO ROLE MAPPING)
// ---------------------------------------------------------

const rawRole = (contextNode.user_role || 'guest').toString();
const effectiveRole = rawRole; // Use role as-is

// ---------------------------------------------------------

const requestType = contextNode.request_type || 'chat';
const userQuery = (contextNode.user_query || '').toLowerCase();
const currentModule = contextNode.module_filter || 'home';
const menuName = contextNode.original_menu_name || 'Menu';

// --- HELPER: Flexible Role Access ---
function checkAccess(allowedRoles, currentRole) {
    if (!allowedRoles) return false;

    let dbRoles = [];

    if (Array.isArray(allowedRoles)) {
        dbRoles = allowedRoles.map(r => r.toString().toLowerCase().trim());
    } 
    else if (typeof allowedRoles === 'string') {
        const cleanString = allowedRoles.replace(/[\[\]"']/g, '');
        dbRoles = cleanString.split(',').map(r => r.trim().toLowerCase());
    }

    const myRole = currentRole.toLowerCase().trim();
    return dbRoles.includes(myRole);
}

// ==========================================
// SCENARIO A: Show Questions List
// ==========================================
if (requestType === 'show_questions') {

    if (currentModule === 'other') {
        return {
            type: 'text',
            text: 'Please visit our support page here: <br><a href="https://vendinaf.com/de/support" target="_blank">Support Page</a>'
        };
    }

    const allowedRows = allRows.filter(row => {
        return checkAccess(row.allowed_roles, effectiveRole);
    });

    const questionsList = allowedRows.map(row => ({
        id: row.intent,
        text: row.button_label
    }));

    let otherLabel = 'Other Query';

    if (questionsList.length === 0) {
        otherLabel = `Other Query (Your Role: '${rawRole}')`;
    }

    questionsList.push({
        id: 'manual_support_link',
        text: otherLabel
    });

    return {
        type: 'questions_list',
        menu: menuName,
        questions: questionsList,
        title: `Questions for ${menuName}:`
    };
}

// ==========================================
// SCENARIO B: Answers
// ==========================================
if (requestType === 'answer_intent' || requestType === 'direct_question' || requestType === 'chat') {

    if (userQuery === 'manual_support_link') {
        return {
            type: 'text',
            text: 'Please visit our support page here: <br><a href="https://vendinaf.com/de/support" target="_blank">Support Page</a>'
        };
    }

    let matchedRow = allRows.find(row =>
        row.intent && row.intent.toLowerCase() === userQuery
    );

    if (!matchedRow) {
        matchedRow = allRows.find(row => {
            if (!row.triggers) return false;
            const triggers = Array.isArray(row.triggers) ? row.triggers : [row.triggers];
            return triggers.some(trigger =>
                userQuery.includes(trigger.toLowerCase())
            );
        });
    }

    if (!matchedRow) {
        return {
            type: 'text',
            text: "I'm sorry, I couldn't find an answer for that."
        };
    }

    if (checkAccess(matchedRow.allowed_roles, effectiveRole)) {
        return {
            type: 'text',
            text: matchedRow.answer
        };
    } 
    else {
        return {
            type: 'text',
            text: `⚠️ Access Denied: Your role (${rawRole}) is not allowed to view this answer.`
        };
    }
}

return {
    type: 'text',
    text: `Error: Unknown request type (${requestType})`
};

return {
  type: 'menu',
  menu: [
      { name: 'Today' },
      { name: 'Weekly Reports' },
      { name: 'Monthly Reports' },
      { name: 'Transactions' },
      { name: 'Taxes'}
  ],
  title: 'Please select a report type:',
  message: 'Choose a timeframe or category below:'
};

