const input = $input.first().json;

// Default module
let module = 'other';

// Get selected menu / submenu safely
const menu =
  input.menu ||
  input.context?.selectedMenu ||
  input.context?.selectedItem ||
  input.context?.menuItem;

// Mapping between menu/submenu and modules
const menuToModule = {
  // Main Menus
  'View': 'view',
  'Manage': 'machines',
  'Maintenance': 'maintenance',
  'Home': 'home',
  'Help': 'other',
  'Franchise': 'franchise',

  // View Submenus
  'Sales Analytics': 'view',
  'Transactions': 'view',

  // Reports (Separate Module)
  'Reports': 'reports',

  // Manage Submenus
  'Vending Machines': 'machines',
  'Inventory': 'inventory',
  'Advertisements': 'advertisements',
  'Membership Cards': 'customers',
  'Discounts': 'discounts',
  'Coupons': 'coupons',
  'Users': 'users',

  // Maintenance Submenus
  'Service Requests': 'maintenance',
  'Spares': 'maintenance',

  // Others

};

// Resolve module
if (menu) {
  module = menuToModule[menu] || menu.toLowerCase().replace(/\s+/g, '_');
}

// Return standardized context
return {
  module_filter: module,
  user_role: input.context?.userRole || input.role || 'guest',
  original_menu_name: menu || null,
  request_type: input.type || 'chat',
  user_query: (input.chatInput || input.query || '').toLowerCase()
};

const role = $json.role || $json.context.userRole;

const menus = {
  'Super Admin': [
    {name: 'Home'},
    {name: 'View', items: ['Sales Analytics', 'Transactions', 'Reports']},
    {name: 'Manage', items: ['Vending Machines', 'Inventory', 'Advertisements', 'Membership Cards', 'Discounts', 'Coupons', 'Users']},
    {name: 'Taxes'},
    {name: 'Maintenance', items: ['Service Requests', 'Spares']},
    {name: 'Franchise'},
    {name: 'Other'}
  ],
  'Admin': [
    {name: 'Home'},
    {name: 'View', items: ['Sales Analytics', 'Transactions','Reports']},
    {name: 'Manage', items: ['Vending Machines', 'Inventory', 'Advertisements', 'Membership Cards', 'Discounts', 'Coupons', 'Users']},
    {name: 'Taxes'},
    {name: 'Maintenance', items: ['Service Requests', 'Spares']},
    {name: 'Other'}
  ],
  'Employee': [
    {name: 'Home'},
    {name: 'Manage', items: ['Vending Machines', 'Inventory', 'Advertisements', 'Membership Cards', 'Discounts', 'Coupons']},
    {name: 'Maintenance', items: ['Service Requests', 'Spares']},
    {name: 'Other'}
  ],

};

return {
  type: 'menu',
  greeting: 'Welcome to NAF Assistant',
  role: role,
  message:'Click any option to learn more, or ask me questions!',
  menu: menus[role] || menus['Employee'],
};

const input = $input.first().json;

// --- 1. SAFE EXTRACTION HELPER ---
// This function looks for data in 'input.key' AND 'input.body.key'
function getParam(key) {
  // Check root level first
  if (input[key] !== undefined && input[key] !== null) return input[key];
  // Check inside 'body' object if it exists
  if (input.body && input.body[key] !== undefined && input.body[key] !== null) return input.body[key];
  return null;
}

// 2. EXTRACT DATA USING HELPER
const rawMessage = getParam('message') || getParam('chatInput') || '';
const message = rawMessage.toString().toLowerCase().trim();
const action = getParam('action') || ''; // Check for specific 'init' action from React

const rawRole = getParam('userAuthority') || getParam('userRole') || 'guest';
const userName = getParam('userName') || 'User';
const franchiseId = getParam('franchiseId') || null; 

const selectedMenu = getParam('selectedMenu') || null;
const selectedIntent = getParam('selectedIntent') || null;

// Generate Session ID if one isn't provided
const sessionId = getParam('sessionId') || 'session-' + Math.random().toString(36).substring(7);

// 3. DETERMINE ROLE (Maps ROLE_ADMIN -> Admin)
let userRole = 'Employee'; // Default fallback
const roleString = rawRole.toString().toLowerCase();

if (roleString.includes('super')) {
  userRole = 'Super Admin';
} else if (roleString.includes('admin')) {
  // This catches 'ROLE_ADMIN', 'Franchise Admin', 'Admin'
  userRole = 'Admin';
} else if (roleString.includes('employee')) {
  userRole = 'Employee';
}

// 4. BUILD CONTEXT
const context = {
  userRole: userRole,
  userName: userName,
  franchiseId: franchiseId, // Important: Passed to AI for filtering
  selectedMenu: selectedMenu,
  selectedIntent: selectedIntent,
  originalMessage: rawMessage, // storing original casing for reference if needed
  sessionId: sessionId
};

// --- LOGIC GATES ---

// Gate 1: INIT / STARTUP
// If React sends { action: 'init' }, we immediately show the Main Menu for the Role.
// We also check for empty message, BUT only if action is not explicitly something else.
if ((message === '' && !selectedMenu && !selectedIntent) || action === 'init' || message === 'start') {
    return {
        type: 'show_menu',
        role: userRole, // Next node will use this to fetch 'Admin' buttons
        context: context
    };
}

// Gate 2: Report Specific Questions & Categories
const reportTypes = ['Today', 'Weekly Reports', 'Monthly Reports', 'Transactions','Taxes'];
const reportQuestions = [
    "How much money was collected in total today?",
    "Which machines are currently out of stock?",
    "Are any machines currently offline or showing errors?",
    "How many people paid by Cash vs. UPI today?",
    "What were the 5 most popular products this week?",
    "Which location made the most sales this week?",
    "Which machines were refilled in the last 7 days?",
    "What is the total revenue for this week?",
    "What was the total profit for this month?",
    "Did we make more money this month than last month?",
    "How many machines needed repairs this month?",
    "Which city is performing the best overall?",
    "Show me the last 10 successful sales.",
    "Show me any transactions that failed today.",
    "How many people used a discount coupon today?",
    "List the most recent refund requests.",
  "January Tax",
        "February Tax",
        "March Tax",
        "April Tax",
        "May Tax",
        "June Tax",
        "July Tax",
        "August Tax",
        "September Tax",
        "October Tax",
        "November Tax",
        "December Tax",
        "Last Month Tax"
];

// If user clicked a specific Report Question
if (selectedIntent && reportQuestions.includes(selectedIntent)) {
    return { 
        type: 'answer_report', 
        chatInput: selectedIntent, 
        context: context 
    };
}

// If user clicked a Report Sub-Category (e.g. "Today")
if (selectedMenu && reportTypes.includes(selectedMenu)) {
    return { 
        type: 'show_report_questions', 
        menu: selectedMenu, 
        context: context 
    };
}

// If user clicked "Reports" from Main Menu
// This logic applies to ALL roles (Admin, Employee, etc.) as long as they clicked the button
if (selectedMenu === 'Reports' || selectedMenu === 'View') {
    return { 
        type: 'show_report_categories', 
        menu: selectedMenu, 
        context: context 
    };
}

// Gate 3: Standard Navigation (Non-Report Menus)
if (selectedIntent) {
  return { 
    type: 'answer_intent', 
    intent: selectedIntent, 
    chatInput: selectedIntent, 
    menu: selectedMenu, 
    context: context 
  };
}
if (selectedMenu) {
  return { 
    type: 'show_questions', 
    menu: selectedMenu, 
    context: context 
  };
}

// Gate 4: AI Question Processing (Direct Typing)
const greetings = ['hi', 'hello', 'hey', 'menu', 'restart', 'test','back to menu','back','show menu','show options','options'];

if (message.length > 1 && !greetings.includes(message)) {
  return {
    type: 'direct_question',
    query: message,
    chatInput: message, 
    context: context
  };
}

// Fallback: Show Main Menu
return {
  type: 'show_menu',
  role: userRole,
  context: context
};

// Access the binary data coming from the HTTP Request node
const binaryData = $input.first().binary;

let fileUrl = null;
let title = 'Report';

// Attempt to get title explicitly from the "Report title" node
try {
    const reportTitleNode = $('Report title').first().json;
    if (reportTitleNode && reportTitleNode.title) {
        title = reportTitleNode.title;
    }
} catch (e) {
    // Default title remains 'Report' if the node data isn't found
    console.log("Could not find 'Report title' node data, using default.");
}

if (binaryData && binaryData.data) {
    const mimeType = 'application/pdf'; // Explicitly set PDF
    const b64 = binaryData.data.data; 

    // Use the standard Data URI format
    fileUrl = `data:${mimeType};base64,${b64}`;
} else {
    return [{ 
        json: { 
            output: { 
                text: "❌ Error: PDF generation failed. No binary data received.",
                pdf_url: null
            } 
        } 
    }];
}

// Clean the title so it is perfectly safe to use as a file name 
// (removes weird characters like /, \, ?, etc. that break file saves)
const safeFileName = title.replace(/[^a-zA-Z0-9 \-_]/g, '').trim() + '.pdf';

return [{ 
    json: { 
        output: {
            text: `✅ Your **${title}** is ready!`,
            pdf_url: fileUrl,
            fileName: safeFileName
        }
    } 
}];

// ============================================================
// 1. Get Merged Data from Input 1 (Index 0)
// ============================================================

let dataRows = [];
try {
  // All data (Data + Title) is coming in through the first input 
  // because of your Merge node.
  dataRows = $input.all(0);
} catch (error) {
  console.log('Input data not found, trying SQL node explicitly');
}

// Fallback to explicitly calling the SQL node if input is empty
if (!dataRows || dataRows.length === 0) {
  try {
    dataRows = $('Execute a SQL query').all();
  } catch (error) {
    console.log('SQL Node data not found');
  }
}

// ============================================================
// 2. Extract Title from the Merged Data
// ============================================================
let rawTitle = '';

// Loop through the incoming data to find where the title is hiding
for (let i = 0; i < dataRows.length; i++) {
  if (dataRows[i].json) {
    if (dataRows[i].json.reportTitle) { rawTitle = dataRows[i].json.reportTitle; break; }
    if (dataRows[i].json.title) { rawTitle = dataRows[i].json.title; break; }
    if (dataRows[i].json.chatInput) { rawTitle = dataRows[i].json.chatInput; break; }
  }
}

// Fallback just in case the Merge dropped it
if (!rawTitle) {
  try {
    rawTitle = $('Detect Message Type1').first().json.chatInput || '';
  } catch (error) {
    console.log('Fallback title not found.');
  }
}

// Function to transform conversational questions into formal titles
function createTitleFromChat(text) {
  if (!text || text.trim() === '') return 'Analytics Report';

  let cleanText = text.replace(/^(show me|give me|tell me|what is|what are|which|find|get)\s+/i, '');
  cleanText = cleanText.replace(/[?!]/g, '').trim();

  let titleCase = cleanText.split(/\s+/).map(word => {
    return word.charAt(0).toUpperCase() + word.slice(1).toLowerCase();
  }).join(' ');

  if (!titleCase.toLowerCase().includes('report')) {
    titleCase += ' Report';
  }

  return titleCase;
}

// Generate the final title
const title = createTitleFromChat(rawTitle);

// ============================================================
// 3. 🧹 CLEANUP: Remove title fields so they aren't columns
// ============================================================
let cleanedDataRows = [];

dataRows.forEach(item => {
  if (item.json) {
    // Delete the metadata keys
    delete item.json.reportTitle;
    delete item.json.title;
    delete item.json.chatInput;
    delete item.json['input 2']; 

    // Only keep rows that still have data left in them 
    // (This prevents an empty row from appearing if your Merge node used "Append" mode)
    if (Object.keys(item.json).length > 0) {
      cleanedDataRows.push(item);
    }
  }
});

dataRows = cleanedDataRows;

// ============================================================
// 🛑 NO DATA HANDLER
// ============================================================
if (!dataRows || dataRows.length === 0) {
  return [{ 
    json: { 
      error: 'NO_DATA',
      message: 'No data found for the requested criteria.',
      summary: 'No records available to generate a report.'
    } 
  }];
}

// ============================================================
// 4. Build Headers & Analyze Columns
// ============================================================
const headersSet = new Set();
dataRows.forEach(item => {
  Object.keys(item.json).forEach(k => headersSet.add(k));
});
const headers = [...headersSet];
const colCount = headers.length;

// ============================================================
// 5. Smart CSS Configuration
// ============================================================
let cssSettings = {};

if (colCount <= 7) {
  cssSettings = {
    zoom: '1',
    fontSize: '11px',
    pageMargin: '10mm',
    tableLayout: 'fixed',
    headerSize: '16px',
    padding: '7px 10px'
  };
} else {
  cssSettings = {
    zoom: '0.75',
    fontSize: '9px',
    pageMargin: '6mm',
    tableLayout: 'auto',
    headerSize: '13px',
    padding: '5px 7px'
  };
}

// ============================================================
// 6. Helper: Escape HTML
// ============================================================
function escapeHtml(text) {
  if (text === null || text === undefined) return '-';
  return String(text)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function formatValue(val) {
  if (val === null || val === undefined || val === '') return '-';
  if (Buffer.isBuffer(val)) return val.toString();
  if (typeof val === 'object' && val !== null) {
    if (val instanceof Date) return val.toISOString().slice(0, 19).replace('T', ' ');
    return JSON.stringify(val);
  }
  return escapeHtml(val);
}

// ============================================================
// 7. Build HTML Table
// ============================================================
const tableHeaders = headers.map(h => `<th>${escapeHtml(h)}</th>`).join('');

const tableRows = dataRows.map((item, index) => {
  const rowCells = headers.map(h => {
    let val = item.json[h];
    return `<td>${formatValue(val)}</td>`;
  }).join('');
  return `<tr>${rowCells}</tr>`;
}).join('');

// ============================================================
// 8. Final HTML Assembly
// ============================================================
const html = `
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<title>${title}</title>
<style>
  /* Page Setup */
  @page { size: A4 landscape; margin: ${cssSettings.pageMargin}; }

  html, body {
    zoom: ${cssSettings.zoom};
    background-color: #ffffff;
  }

  body {
    font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif;
    font-size: ${cssSettings.fontSize};
    margin: 0;
    padding: 0;
    color: #333;
  }

  /* ── Title ── */
  h2 {
    text-align: center;
    margin: 14px 0 18px 0;
    font-size: ${cssSettings.headerSize};
    font-weight: 700;
    color: #111;
    letter-spacing: 0.02em;
  }

  /* ── Table Shell ── */
  .report-table {
    width: 100%;
    border-collapse: collapse;
    table-layout: ${cssSettings.tableLayout};
    border: 1px solid #c0c0c0;
  }

  /* ── Header Row ── */
  .report-table thead tr {
    background-color: #2a7dd4;   
  }

  .report-table th {
    background-color: #2a7dd4;
    color: #ffffff;
    font-weight: 700;
    font-size: 0.92em;
    text-transform: uppercase;
    letter-spacing: 0.04em;
    padding: ${cssSettings.padding};
    border: 1px solid #1f63aa;
    white-space: nowrap;
    text-align: left;
  }

  /* ── Data Rows ── */
  .report-table td {
    border: 1px solid #d6d6d6;
    padding: ${cssSettings.padding};
    text-align: left;
    vertical-align: middle;
    word-wrap: break-word;
    color: #333;
  }

  /* White base row */
  .report-table tbody tr {
    background-color: #ffffff;
  }

  /* Light gray alternate row */
  .report-table tbody tr:nth-child(even) {
    background-color: #f5f8fc;
  }

  /* Subtle hover highlight */
  .report-table tbody tr:hover {
    background-color: #e8f0fb;
  }
</style>
</head>
<body>

<h2>${title}</h2>

<table class="report-table">
  <thead>
    <tr>
      ${tableHeaders}
    </tr>
  </thead>
  <tbody>
    ${tableRows}
  </tbody>
</table>

</body>
</html>
`;

// ============================================================
// 9. Output Binary
// ============================================================
const buffer = Buffer.from(html, 'utf8');

return [
  {
    json: {
      fileName: 'index.html',
      columnCount: colCount,
      reportTitle: title,
      status: 'success'
    },
    binary: {
      data: {
        data: buffer.toString('base64'),
        mimeType: 'text/html',
        fileName: 'index.html'
      }
    }
  }
];

