// ============================================================
// 3. HTML Builders
// ============================================================

function escapeHtml(val) {
  if (val === null || val === undefined || val === '') return '-';
  return String(val)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// ── Format column header: camelCase / snake_case → Title Case ──
function formatHeader(col) {
  return col
    .replace(/_/g, ' ')
    .replace(/([a-z])([A-Z])/g, '$1 $2')
    .replace(/\b\w/g, c => c.toUpperCase());
}

// ── Format cell value: add € prefix to amount-like columns ──
function formatValue(col, val) {
  if (val === null || val === undefined || val === '') return '-';
  const colLower = col.toLowerCase();
  const isAmount = /amount|price|revenue|sales|gross|net|taxable|total(?!transactions|items|count|products)/i.test(colLower);
  const num = parseFloat(val);
  if (isAmount && !isNaN(num)) {
    return '€' + num.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  }
  return String(val);
}

// ── Build report table (from report:true format) ──
function buildReportTable(columns, rows) {
  let html = `<table><thead><tr>`;
  columns.forEach(col => {
    html += `<th>${escapeHtml(formatHeader(col))}</th>`;
  });
  html += `</tr></thead><tbody>`;
  rows.forEach(row => {
    html += `<tr>`;
    columns.forEach(col => {
      let val = row[col];
      if (typeof val === 'object' && val !== null) val = JSON.stringify(val);
      html += `<td>${escapeHtml(formatValue(col, val))}</td>`;
    });
    html += `</tr>`;
  });
  html += `</tbody></table>`;
  return html;
}

// ── Build standard layout table ──
function buildTable(component) {
  const title = component.title || '';
  const columns = component.columns || [];
  const rows = component.rows || [];
  let html = `<div class="section-title">${escapeHtml(title)}</div>`;
  html += `<table><thead><tr>`;
  columns.forEach(col => { html += `<th>${escapeHtml(col)}</th>`; });
  html += `</tr></thead><tbody>`;
  rows.forEach(row => {
    html += `<tr>`;
    columns.forEach(col => {
      let val = row[col];
      if (typeof val === 'object' && val !== null) val = JSON.stringify(val);
      html += `<td>${escapeHtml(val)}</td>`;
    });
    html += `</tr>`;
  });
  html += `</tbody></table>`;
  return html;
}

// ── Build leaderboard ──
function buildLeaderboard(component) {
  const title = component.title || '';
  const data = component.data || [];
  let html = `<div class="section-title">${escapeHtml(title)}</div>`;
  html += `<table class="leaderboard"><thead><tr><th>#</th><th>Name</th><th>Value</th></tr></thead><tbody>`;
  data.forEach((item, index) => {
    const rank = index + 1;
    let badgeClass = '';
    if (rank === 1) badgeClass = 'gold';
    else if (rank === 2) badgeClass = 'silver';
    else if (rank === 3) badgeClass = 'bronze';
    html += `<tr>
      <td><span class="rank-badge ${badgeClass}">${rank}</span></td>
      <td>${escapeHtml(item.label)}</td>
      <td><strong>${escapeHtml(item.value)}</strong></td>
    </tr>`;
  });
  html += `</tbody></table>`;
  return html;
}

// ── Build KPI/metric table ──
function buildKPI(component) {
  const title = component.title || '';
  const data = component.data || [];
  let html = `<div class="section-title">${escapeHtml(title)}</div>`;
  html += `<table><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody>`;
  data.forEach(item => {
    html += `<tr><td>${escapeHtml(item.label)}</td><td><strong>${escapeHtml(item.value)}</strong></td></tr>`;
  });
  html += `</tbody></table>`;
  return html;
}

// ── Build KPI cards (kpi_card type from layout) ──
function buildKPICards(cards) {
  let html = `<div class="kpi-grid">`;
  cards.forEach(card => {
    html += `<div class="kpi-card">
      <div class="kpi-title">${escapeHtml(card.title)}</div>
      <div class="kpi-value">${escapeHtml(card.value)}</div>
    </div>`;
  });
  html += `</div>`;
  return html;
}

// ============================================================
// 4. Branch: report:true vs layout array
// ============================================================
const summary = parsedResponse.summary || '';
const isReport = parsedResponse.report === true;

let pageTitle = 'Report';
let bodyContent = '';

if (summary) {
  bodyContent += `<div class="summary">${escapeHtml(summary)}</div>`;
}

if (isReport) {
  // ── REPORT MODE: render columns + rows as a styled table ──
  const columns = parsedResponse.columns || [];
  const rows    = parsedResponse.rows    || [];

  // Derive a better page title from the summary
  if (summary) {
    const match = summary.match(/(?:gross|net|taxable|tax|transaction|revenue|sales)/i);
    pageTitle = match ? 'Tax Report' : 'Report';
  }

  if (columns.length > 0 && rows.length > 0) {
    bodyContent += buildReportTable(columns, rows);
  } else {
    bodyContent += `<p style="text-align:center;color:#666;">No data available.</p>`;
  }

} else {
  // ── LAYOUT MODE: render visual components ──
  const layout = parsedResponse.layout || [];

  // Derive page title from first component
  if (layout.length > 0 && layout[0].title) {
    pageTitle = layout[0].title;
  }

  if (layout.length === 0) {
    bodyContent += `<p style="text-align:center;color:#666;">${escapeHtml(summary || 'No data available.')}</p>`;
  } else {
    // Collect consecutive kpi_cards and render as a grid
    let i = 0;
    while (i < layout.length) {
      const component = layout[i];
      const type = (component.type || '').toLowerCase();

      if (type === 'kpi_card') {
        // Gather all adjacent kpi_cards
        const cards = [];
        while (i < layout.length && (layout[i].type || '').toLowerCase() === 'kpi_card') {
          cards.push(layout[i]);
          i++;
        }
        bodyContent += buildKPICards(cards);
      } else {
        if (type === 'table') {
          bodyContent += buildTable(component);
        } else if (type === 'leaderboard') {
          bodyContent += buildLeaderboard(component);
        } else if (type === 'kpi' || type === 'metric' || type === 'metrics') {
          bodyContent += buildKPI(component);
        } else {
          // Unknown type — fallback
          if (component.columns && component.rows) {
            bodyContent += buildTable(component);
          } else if (component.data) {
            bodyContent += buildLeaderboard(component);
          }
        }
        i++;
      }
    }
  }
}

// ============================================================
// 5. Assemble Final HTML
// ============================================================
const html = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<title>${escapeHtml(pageTitle)}</title>
<style>${sharedCSS}</style>
</head>
<body>
<h2>${escapeHtml(pageTitle)}</h2>
${bodyContent}
<div class="footer">Generated on ${new Date().toLocaleString()}</div>
</body>
</html>`;

// ============================================================
// 6. Output as Binary HTML file
// ============================================================
const buffer = Buffer.from(html, 'utf-8');

return [{
  json: {
    title: pageTitle,
    summary: summary,
    isReport: isReport,
    layoutTypes: isReport ? ['report_table'] : (parsedResponse.layout || []).map(c => c.type)
  },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];

