  const hasSuggestions = fallbackMessage.toLowerCase().includes("did you mean something like");

  if (hasSuggestions) {
    // Split the text into the main message and the suggestions part
    const parts = fallbackMessage.split(/did you mean something like:?/i);

    // Reconstruct the intro message
