      // Look for standard bullets (*, -, •) or numbers (1., 2.)
      const bulletMatches = suggestionsText.match(/(?:^|\n)\s*(?:[•\-\*]|\d+\.)\s*(.+)/g);

      if (bulletMatches && bulletMatches.length > 0) {
        suggestions = bulletMatches.map(b => 
          b.replace(/^\s*(?:[•\-\*]|\d+\.)\s*/, "") // Remove the bullet/number
           .replace(/^['"]|['"]$/g, "")             // Remove quotes
           .trim()
        );
      } else {
        // If no bullets are found, assume it's a comma-separated list
        let firstLine = suggestionsText.split('\n')[0];
